  ('diplomatic-9e854390-moex-00336', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '假設其他條件相同情況下，下列何種公司債的殖利率最高？', '["可轉換公司債", "可贖回公司債", "可賣回公司債", "普通公司債"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00337', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司X1年之稅前淨利為$3,460,000，所得稅率25%，加權平均流通在外之普通股為250,000股， 當年度宣告並支付特別股股利$95,000及普通股股利$132,000，則甲公司X1年度普通股之每股盈 餘為：', '["$9.472", "$9.852", "$10", "$10.38"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00338', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司有一應付公司債流通在外，每年底付息，X1年期初與期末應付公司債之攤銷後成本分別為 $851,706以及$840,606，X1年度淨利與利息費用分別為$113,100以及$103,500。該公司之會計政 策係將支付利息列為營業活動，若以間接法計算營業活動現金流量，下列調整何者正確？', '["加回公司債折價攤銷$11,100", "扣除公司債折價攤銷$11,100", "加回公司債溢價攤銷$11,100", "扣除公司債溢價攤銷$11,100"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00339', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司X1年部分資產及負債之期初與期末金額如下： 項目 期初 期末 應收帳款 $3,200 $2,950 土地 30,000 32,000 應付帳款 2,640 2,930 預付保險費 1,800 1,650 預收收入 1,230 1,320 應付公司債（平價發行） 6,000 5,800 存貨 1,760 1,940 甲公司X1年稅後淨利為$11,600，所得稅費用及支付金額為$1,200，則甲公司X1年之來自營業活 動現金流量為：', '["$10,000", "$11,900", "$12,200", "$13,400"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00340', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司X9年度銷貨收入總額$200,000、銷貨退回$1,000，當年度提列之預期信用損失$4,400，且 X9年度中曾發生部分應收帳款確定無法收回被沖銷，X8年與X9年底帳上應收帳款、備抵損失 餘額列示如下，則X9年度之銷貨收現數為何？ X8年底 X9年底 應收帳款 $150,000 $180,000 減：備抵損失 (9,600) (9,000) 應收帳款淨額 $140,400 $171,000', '["$170,000", "$169,000", "$164,000", "$160,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00341', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司於X1年12月31日以每股$24將1,000股之庫藏股再度發行，而該庫藏股係於X1年1月 31日以每股$28購入。甲公司會計人員分析庫藏股再發行之交易對於財務報表的影響，包含下列', '["淨利率減少", "流動比率增加", "負債比率增加", "總資產週轉率減少  ⑤總資產報酬 率增加  ⑥權益報酬率增加 請問上列"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00342', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '依司法院釋字第499號解釋，修憲應循正當修憲程序為之，如有下列何種瑕疵，即不生其應有之效力？', '["重大瑕疵", "明顯瑕疵", "明顯錯誤瑕疵", "明顯重大瑕疵"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00343', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '有關中華民國國防，下列敘述何者錯誤？', '["目的在於保衛國家安全，維護世界和平", "武力包含陸海空軍", "現役軍人得兼任文官", "保持政治中立"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00344', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '依憲法規定及相關學理，關於軍事審判權，下列敘述何者最為正確？', '["憲法第9條明文保障非現役軍人不受軍事審判", "為維護軍紀，軍事法院判決應經國防部部長之核可", "憲法第9條明文規定現役軍人應受軍事審判", "法律不得規定僅軍事審判機關對軍人犯罪有專屬審判權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00345', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '監獄檢閱受刑人書信時，不得有下列何種行為？', '["確認有無夾帶違禁品", "區分書信種類，斟酌個案情形，以判斷監獄長官能否閱讀書信之內容", "基於維護監獄紀律所必要而刪除書信部分內容，並保留書信全文影本，俟受刑人出獄時發還之", "對受刑人所撰寫文稿之內容，審查其題意是否正確或有無損害監獄信譽"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL)
